<template><div class="min-h-screen bg-slate-100 p-6"><div class="mx-auto max-w-6xl"><div class="mb-6 flex justify-between"><h1 class="text-3xl font-black">Course Management</h1><RouterLink to="/admin" class="rounded bg-white px-4 py-2 font-bold">Users</RouterLink></div><form class="rounded bg-white p-5" @submit.prevent="save"><input v-model="form.title" class="field" placeholder="Course title"><textarea v-model="form.description" class="field" placeholder="Description"></textarea><label class="mb-4 block"><input v-model="form.isPremium" type="checkbox"> Premium course</label><button class="rounded bg-emerald-700 px-5 py-3 font-bold text-white">Create Course</button></form><div class="mt-6 rounded bg-white"><div v-for="course in courses" :key="course.id" class="border-b p-5"><h2 class="font-black">{{ course.title }}</h2><p class="text-sm text-slate-600">{{ course.description }}</p></div></div><p v-if="error" class="mt-4 text-red-600">{{ error }}</p></div></div></template>
<script setup lang="ts">import { onMounted,ref } from 'vue';import { apiUrl } from '../services/api';import { fetchCourses,type ApiCourse } from '../services/courseService';const courses=ref<ApiCourse[]>([]);const error=ref('');const form=ref({title:'',description:'',isPremium:false});async function load(){try{courses.value=await fetchCourses()}catch(e:any){error.value=e.message}}async function save(){const token=localStorage.getItem('yckf_token');if(!token){error.value='Login first';return}const res=await fetch(apiUrl('/api/courses'),{method:'POST',headers:{Authorization:`Bearer ${token}`,'Content-Type':'application/json'},body:JSON.stringify({...form.value,lessons:[]})});if(!res.ok){error.value='Failed to create course';return}form.value={title:'',description:'',isPremium:false};load()}onMounted(load);</script><style scoped>.field{margin-bottom:1rem;width:100%;border:1px solid #cbd5e1;border-radius:.375rem;padding:.85rem}</style>
